@@ -10,7 +10,17 @@ class WebhookDispatcher
     public function send(string $url, array $payload): void
     {
-        Http::post($url, $payload);
+        $attempts = 0;
+        do {
+            $response = Http::post($url, $payload);
+            $attempts++;
+            if ($response->successful() || $response->status() < 500) {
+                return;
+            }
+            usleep((2 ** $attempts) * 100000);
+        } while ($attempts < 3);
+
+        Log::warning('Webhook delivery failed after retries', ['url' => $url]);
     }
 }
